import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A cute pixel art dragon';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-standard', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com/v1',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/v1/generations': {
      response: {
        type: 'json-value',
        body: {
          images: [{ base64: 'dGVzdC1pbWFnZS1kYXRh' }],
        },
      },
    },
  });

  describe('doGenerate', () => {
    it('passes the correct parameters', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '64x64',
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        model: 'pixelart-standard',
        n: 1,
        size: '64x64',
        seed: 42,
      });
    });

    it('passes provider options for style and pixel density', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelArt: {
            style: 'retro',
            pixelDensity: 2,
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        model: 'pixelart-standard',
        n: 1,
        style: 'retro',
        pixel_density: 2,
      });
    });

    it('returns base64 images from the response', async () => {
      server.urls['https://api.example.com/v1/generations'].response = {
        type: 'json-value',
        body: {
          images: [
            { base64: 'aW1hZ2UxZGF0YQ==' },
            { base64: 'aW1hZ2UyZGF0YQ==' },
          ],
        },
      };

      const model = createBasicModel();
      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
